// Get email data from trigger and labels
const email = $('Gmail Trigger').first().json;
const allLabels = $('Get All Labels').all().map(item => item.json);

const from = (email.from || '').toLowerCase();
const subject = (email.subject || '').toLowerCase();

// Define categorization rules
const rules = {
  work: [
    'slack.com', 'notion.so', 'atlassian', 'jira', 'confluence',
    'github.com', 'gitlab', 'bitbucket', 'asana', 'monday.com',
    'zoom.us', 'teams', 'meet.google', 'calendar'
  ],
  newsletters: [
    'newsletter', 'digest', 'weekly', 'update', 'substack',
    'mailchimp', 'sendinblue', 'constantcontact', 'unsubscribe'
  ],
  social: [
    'facebook', 'twitter', 'instagram', 'linkedin', 'tiktok',
    'youtube', 'reddit', 'discord', 'whatsapp', 'telegram'
  ],
  finance: [
    'bank', 'paypal', 'stripe', 'invoice', 'payment', 'transaction',
    'receipt', 'billing', 'subscription', 'credit', 'debit'
  ],
  personal: [
    'gmail.com', 'outlook.com', 'hotmail.com', 'yahoo.com',
    'icloud.com', 'protonmail'
  ]
};

// Label name mapping
const labelMapping = {
  'work': 'Work',
  'newsletters': 'Newsletters', 
  'social': 'Social Media',
  'finance': 'Finance',
  'personal': 'Personal',
  'other': 'To Review'
};

// Determine category
let category = 'other';
for (const [cat, patterns] of Object.entries(rules)) {
  for (const pattern of patterns) {
    if (from.includes(pattern) || subject.includes(pattern)) {
      category = cat;
      break;
    }
  }
  if (category !== 'other') break;
}

// Find label ID
const labelName = labelMapping[category];
const label = allLabels.find(l => l.name === labelName);

if (!label) {
  throw new Error(`Label "${labelName}" not found. Please run the "Gmail Labels Setup" workflow first.`);
}

return [{
  json: {
    messageId: email.id,
    from: email.from,
    subject: email.subject,
    category: category,
    labelName: labelName,
    labelId: label.id
  }
}];
